// wikiraceDevPlugin.ts
function wikiraceDevPlugin() {
  return {
    name: "wikirace-dev-api",
    configureServer(server) {
      const api = express();
      api.use(cors({ origin: true }));
      api.use(express.json());
      attachApiRoutes(api);
      server.middlewares.use((req, res, next) => {
        const url = req.url ?? "";
        if (url.startsWith("/api")) {
          api(req, res, next);
        } else {
          next();
        }
      });
      const httpServer = server.httpServer;
      if (!httpServer) {
        console.warn("[wikirace] httpServer indisponible : Socket.io non attach\xE9");
        return;
      }
      const io = new Server(httpServer, { cors: { origin: true } });
      attachSocketIO(io);
    }
  };
}

